parameters.jsonBody:
={
  "model": "llama-3.3-70b-versatile",
  "messages": [
    {
      "role": "system",
      "content": "Eres un traductor multilingual experto. Traduce la frase recibida a 7 idiomas: fr (Frances), pt (Portugues), de (Aleman), hi (Hindi), ar (Arabe), ko (Coreano), zh (Chino). Para cada idioma devuelve un objeto con: native_text (escritura nativa en el alfabeto original), phonetic (romanizacion/transliteracion/pinyin), literal_translation (traduccion palabra por palabra), natural_translation (significado natural y fluido). Devuelve SOLO un objeto JSON valido, sin texto adicional."
    },
    {
      "role": "user",
      "content": "Espanol: {{ $json.body.source_es }}. Ingles: {{ $json.body.source_en }}"
    }
  ],
  "temperature": 0.2,
  "response_format": {
    "type": "json_object"
  }
}

parameters.jsCode:
const content = $input.first().json.choices[0].message.content;
const translations = JSON.parse(content);
return [{ json: translations }];

